module top_module(
  input clk,
  input reset_n,
  output [3:0] count
);reg [3:0] unused_counter = 4'd0;

  always @(posedge clk, negedge reset_n) begin
    if (!reset_n) begin
      unused_counter <= 4'd0;
    end else if (unused_counter == 4'd9) begin
      unused_counter <= 4'd0;
    end else begin
      unused_counter <= unused_counter + 1;
    end
  end

  assign count = unused_counter;

endmodule
